let raw = $.steps.transformItem.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { item: $.loop.item, result: raw }; }

const iterations = $.steps.processLoop.response.iterations || [];
const results = [];
iterations.forEach(function(iter) {
  var parsed = (iter.parseItemResult && iter.parseItemResult.output) ? iter.parseItemResult.output : {};
  results.push({ item: parsed.item || 'Unknown', result: parsed.result || 'No result' });
});
var total = $.steps.parseItems.output.count;
return { results, total, processed: results.length };

var data = $.steps.collectResults.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':repeat: Batch Processing Complete', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Processed ' + data.processed + ' of ' + data.total + ' items*' } });
blocks.push({ type: 'divider' });
data.results.forEach(function(r, i) {
  var resultText = typeof r.result === 'string' ? r.result : JSON.stringify(r.result);
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (i + 1) + '. ' + r.item + '*\n' + resultText.slice(0, 500) } });
});
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':gear: Batch processed with Claude AI via One CLI' }] });
var fallback = 'Batch Processing: ' + data.processed + ' items completed';
return { blocks, fallback };
